import React, { useState } from 'react';
import SEOHead from '../components/SEOHead';

const COLORS = [
  { name: 'Black',  hex: '#1a1a1a', digit: 0, multiplier: 1,       tolerance: null,  tempco: 250 },
  { name: 'Brown',  hex: '#7B3F00', digit: 1, multiplier: 10,      tolerance: '±1%', tempco: 100 },
  { name: 'Red',    hex: '#CC0000', digit: 2, multiplier: 100,     tolerance: '±2%', tempco: 50  },
  { name: 'Orange', hex: '#FF8C00', digit: 3, multiplier: 1000,    tolerance: null,  tempco: 15  },
  { name: 'Yellow', hex: '#FFD700', digit: 4, multiplier: 10000,   tolerance: null,  tempco: 25  },
  { name: 'Green',  hex: '#228B22', digit: 5, multiplier: 100000,  tolerance: '±0.5%', tempco: 20 },
  { name: 'Blue',   hex: '#0000CD', digit: 6, multiplier: 1000000, tolerance: '±0.25%', tempco: 10 },
  { name: 'Violet', hex: '#8B008B', digit: 7, multiplier: 10000000,tolerance: '±0.1%', tempco: 5  },
  { name: 'Grey',   hex: '#808080', digit: 8, multiplier: 100000000,tolerance:'±0.05%',tempco: 1  },
  { name: 'White',  hex: '#E8E8E8', digit: 9, multiplier: 1000000000, tolerance: null, tempco: null },
  { name: 'Gold',   hex: '#CFB53B', digit: null, multiplier: 0.1,  tolerance: '±5%', tempco: null },
  { name: 'Silver', hex: '#C0C0C0', digit: null, multiplier: 0.01, tolerance: '±10%',tempco: null },
];

const digitColors = COLORS.filter(c => c.digit !== null);
const multColors  = COLORS.filter(c => c.multiplier !== null);
const tolColors   = COLORS.filter(c => c.tolerance !== null);
const tempColors  = COLORS.filter(c => c.tempco !== null);

const formatR = (R) => {
  if (R >= 1e9) return `${(R/1e9).toFixed(3)} GΩ`;
  if (R >= 1e6) return `${(R/1e6).toFixed(3)} MΩ`;
  if (R >= 1e3) return `${(R/1e3).toFixed(3)} kΩ`;
  return `${R.toFixed(3)} Ω`;
};

export default function ResistorColorCode() {
  const [bands, setBands] = useState(4);
  const [sel, setSel] = useState({ b1: 'Brown', b2: 'Black', b3: null, b4: 'Red', b5: 'Gold', b6: null });
  const [result, setResult] = useState(null);

  const handleBand = (band, colorName) => {
    setSel(s => ({ ...s, [band]: colorName }));
    setResult(null);
  };

  const calculate = () => {
    const c = (name) => COLORS.find(c => c.name === name);
    let val, tol, tc;
    if (bands === 4) {
      const [b1,b2,b4,b5] = [c(sel.b1), c(sel.b2), c(sel.b4), c(sel.b5)];
      if (!b1||!b2||!b4||!b5) return;
      val = (b1.digit * 10 + b2.digit) * b4.multiplier;
      tol = b5.tolerance;
    } else if (bands === 5) {
      const [b1,b2,b3,b4,b5] = [c(sel.b1),c(sel.b2),c(sel.b3),c(sel.b4),c(sel.b5)];
      if (!b1||!b2||!b3||!b4||!b5) return;
      val = (b1.digit*100 + b2.digit*10 + b3.digit) * b4.multiplier;
      tol = b5.tolerance;
    } else {
      const [b1,b2,b3,b4,b5,b6] = [c(sel.b1),c(sel.b2),c(sel.b3),c(sel.b4),c(sel.b5),c(sel.b6)];
      if (!b1||!b2||!b3||!b4||!b5||!b6) return;
      val = (b1.digit*100 + b2.digit*10 + b3.digit) * b4.multiplier;
      tol = b5.tolerance;
      tc = b6.tempco;
    }
    setResult({ val, tol, tc });
  };

  const valueToColor = (val) => {
    if (!val || isNaN(val)) return;

    // Simple 4-band logic for bidirectional
    let str = Math.floor(val).toString();
    let d1, d2, mult;

    if (str.length >= 2) {
      d1 = parseInt(str[0]);
      d2 = parseInt(str[1]);
      mult = Math.pow(10, str.length - 2);
    } else {
      d1 = 0;
      d2 = parseInt(str[0]);
      mult = 1;
    }

    const b1 = COLORS.find(c => c.digit === d1)?.name;
    const b2 = COLORS.find(c => c.digit === d2)?.name;
    const b4 = COLORS.find(c => c.multiplier === mult)?.name;

    if (b1 && b2 && b4) {
      setSel(s => ({ ...s, b1, b2, b4, b3: null, b5: 'Gold' }));
      setBands(4);
    }
  };

  const ColorSelect = ({ bandKey, label, options }) => (
    <div className="input-group">
      <label>{label}</label>
      <div style={{display:'flex',gap:'8px',alignItems:'center'}}>
        <select value={sel[bandKey] || ''} onChange={e => handleBand(bandKey, e.target.value)} style={{flex:1}}>
          <option value="">-- Select --</option>
          {options.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
        </select>
        {sel[bandKey] && (
          <div style={{width:'28px',height:'28px',borderRadius:'6px',background:COLORS.find(c=>c.name===sel[bandKey])?.hex,border:'1px solid var(--border)',flexShrink:0}} />
        )}
      </div>
    </div>
  );

  const activeBands = () => {
    const keys = bands === 4 ? ['b1','b2','b4','b5'] : bands === 5 ? ['b1','b2','b3','b4','b5'] : ['b1','b2','b3','b4','b5','b6'];
    return keys.map(k => sel[k]).filter(Boolean).map(name => COLORS.find(c=>c.name===name));
  };

  return (
    <>
      <SEOHead
        title="Resistor Color Code Calculator – 4, 5, 6 Band | PoolCalculator"
        description="Decode resistor color codes for 4-band, 5-band, and 6-band resistors. Select colors to get resistance value and tolerance instantly."
        keywords="resistor color code calculator, 4 band resistor, 5 band resistor, 6 band resistor, resistance calculator"
        canonical="/resistor-color-code"
      />
      <div className="page-wrapper">
        <div className="container">
          <div className="ad-slot ad-slot-banner">Top Banner Advertisement</div>
          <div className="page-header">
            <h1>Resistor Color Code Calculator</h1>
            <p>Select color bands to decode any 4-band, 5-band, or 6-band resistor value.</p>
          </div>

          <div className="calc-layout">
            <div className="card">
              <div className="section-title">Band Configuration</div>
              <div className="input-group">
                <label>Number of Bands</label>
                <select value={bands} onChange={e => { setBands(+e.target.value); setResult(null); }}>
                  <option value={4}>4 Band</option>
                  <option value={5}>5 Band</option>
                  <option value={6}>6 Band</option>
                </select>
              </div>
              <ColorSelect bandKey="b1" label="Band 1 (1st digit)" options={digitColors} />
              <ColorSelect bandKey="b2" label="Band 2 (2nd digit)" options={digitColors} />
              {bands >= 5 && <ColorSelect bandKey="b3" label="Band 3 (3rd digit)" options={digitColors} />}
              <ColorSelect bandKey="b4" label={bands >= 5 ? 'Band 4 (Multiplier)' : 'Band 3 (Multiplier)'} options={multColors} />
              <ColorSelect bandKey="b5" label={bands >= 5 ? 'Band 5 (Tolerance)' : 'Band 4 (Tolerance)'} options={tolColors} />
              {bands === 6 && <ColorSelect bandKey="b6" label="Band 6 (Temp. Coefficient)" options={tempColors} />}
              <div style={{marginTop:'32px'}}>
                <div className="section-title">Value to Color Code</div>
                <div className="input-group">
                  <label>Resistance Value (Ω)</label>
                  <input 
                    type="number" 
                    placeholder="e.g. 1000" 
                    onChange={e => valueToColor(parseFloat(e.target.value))}
                  />
                </div>
              </div>
              <button className="btn-primary" onClick={calculate} style={{marginTop:'12px'}}>Decode Bands</button>
            </div>

            <div className="hero-image-container">
              <img src="/images/calculator_resistor.png" alt="Resistor Color Code Chart" className="hero-img" />
            </div>
          </div>

          {result && (
            <div className="result-section">
              <div className="card">
                <div className="section-title">Calculation Results</div>
                <div className="result-box">
                  <div className="result-item highlight">
                    <span className="result-label">Total Resistance</span>
                    <span className="result-value">{formatR(result.val)}</span>
                  </div>
                  {result.tol && (
                    <div className="result-item">
                      <span className="result-label">Tolerance</span>
                      <span className="result-value" style={{color:'var(--warning)'}}>{result.tol}</span>
                    </div>
                  )}
                  {result.tc && (
                    <div className="result-item">
                      <span className="result-label">Temp. Coefficient</span>
                      <span className="result-value">{result.tc} ppm/°C</span>
                    </div>
                  )}
                </div>
              </div>
              <div className="ad-slot ad-slot-banner">Below Result Advertisement</div>
            </div>
          )}

          <div className="description-section card">
            <div className="description-layout">
              <div className="description-image">
                <img src="/images/calculator_descrip_resistor.png" alt="How to read resistor color bands" />
              </div>
              <div className="description-text">
                <div className="section-title">Understanding Resistor Color Codes</div>
                <p>
                  Resistors use colored bands to indicate their resistance value, tolerance, and sometimes reliability or temperature coefficient. 
                  The first two (or three) bands represent digits, followed by a multiplier band, and finally a tolerance band.
                </p>
                <div className="formula-box">
                  <h3>The Calculation</h3>
                  <p>Value = (Significant Digits) × 10<sup>Multiplier</sup></p>
                  <p style={{fontSize:'13px', marginTop:'6px', color:'var(--text-muted)'}}>Example (4-Band): Brown (1), Black (0), Red (×100), Gold (±5%) = 10 × 100 = 1000 Ω (1kΩ) ±5%.</p>
                </div>
                <div className="example-box">
                  <h3>Pro Tip</h3>
                  <p>Hold the resistor so that the tolerance band (usually Gold or Silver) is on the right side. Start reading from left to right.</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
